import{_ as e,o as a,c as r,S as o}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"Temperature 与采样策略","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_18-temperature.md","filePath":"直击概念/17ai/s_ai_18-temperature.md","lastUpdated":1778207238000}'),d={name:"直击概念/17ai/s_ai_18-temperature.md"};function i(l,t,n,s,h,p){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="temperature-与采样策略" tabindex="-1">Temperature 与采样策略 <a class="header-anchor" href="#temperature-与采样策略" aria-label="Permalink to &quot;Temperature 与采样策略&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>Temperature（温度参数）控制 LLM 输出的<strong>随机性</strong>和<strong>创造性</strong>。它是生成多样性文本 vs 确定性文本的核心开关。</p><p>采样策略则决定了从概率分布中<strong>如何选择</strong>下一个 token——是选最可能的一个，还是按概率随机选。</p><h2 id="temperature" tabindex="-1">Temperature <a class="header-anchor" href="#temperature" aria-label="Permalink to &quot;Temperature&quot;">​</a></h2><p>在 Softmax 之前除以温度 T：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>P(token_i) = softmax(logits_i / T)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="t-值的影响" tabindex="-1">T 值的影响 <a class="header-anchor" href="#t-值的影响" aria-label="Permalink to &quot;T 值的影响&quot;">​</a></h3><table><thead><tr><th>T 值</th><th>效果</th><th>适用场景</th></tr></thead><tbody><tr><td>0 ~ 0.3</td><td>高度确定，几乎总是选最高概率 token</td><td>代码生成、事实性问答、翻译</td></tr><tr><td>0.5 ~ 0.8</td><td>适中创造性</td><td>一般对话、摘要</td></tr><tr><td>0.8 ~ 1.2</td><td>较高创造性</td><td>创意写作、头脑风暴</td></tr><tr><td>1.5 ~ 2.0</td><td>高度随机</td><td>艺术性文本、多样性需求</td></tr></tbody></table><h3 id="极端值" tabindex="-1">极端值 <a class="header-anchor" href="#极端值" aria-label="Permalink to &quot;极端值&quot;">​</a></h3><ul><li><strong>T → 0</strong>：输出几乎完全确定（多次生成相同 prompt，结果高度一致），等价于贪心解码</li><li><strong>T → ∞</strong>：所有 token 概率趋同，输出近乎随机乱码</li></ul><h2 id="采样策略" tabindex="-1">采样策略 <a class="header-anchor" href="#采样策略" aria-label="Permalink to &quot;采样策略&quot;">​</a></h2><h3 id="贪心解码-greedy-decoding" tabindex="-1">贪心解码（Greedy Decoding） <a class="header-anchor" href="#贪心解码-greedy-decoding" aria-label="Permalink to &quot;贪心解码（Greedy Decoding）&quot;">​</a></h3><p>每次选概率<strong>最高</strong>的 token：极其确定但缺乏多样性。</p><blockquote><p>The cat sat on the ... → &quot;mat&quot;（每次都一样）</p></blockquote><h3 id="top-k-采样" tabindex="-1">Top-k 采样 <a class="header-anchor" href="#top-k-采样" aria-label="Permalink to &quot;Top-k 采样&quot;">​</a></h3><p>只从概率最高的 <strong>k 个</strong> token 中按概率采样。限制候选池，防止选到极低概率 token。</p><ul><li>k=1：等价于贪心解码</li><li>k=50：常见设置，平衡质量与多样性</li></ul><h3 id="top-p-采样-核采样-nucleus-sampling" tabindex="-1">Top-p 采样（核采样 / Nucleus Sampling） <a class="header-anchor" href="#top-p-采样-核采样-nucleus-sampling" aria-label="Permalink to &quot;Top-p 采样（核采样 / Nucleus Sampling）&quot;">​</a></h3><p>从累计概率达到 <strong>p</strong> 的最少 token 中采样。动态调整候选池大小：</p><ul><li>p=0.1：只从最高概率 token 中选（很保守）</li><li>p=0.9：几乎覆盖所有合理选项（常见设置）</li></ul><p><strong>Top-k vs Top-p</strong>：</p><ul><li>Top-k 固定候选数量，对低概率分布可能太宽或太窄</li><li>Top-p 动态调整，更智能化 → 现代 LLM 通常两者结合使用</li></ul><h3 id="beam-search" tabindex="-1">Beam Search <a class="header-anchor" href="#beam-search" aria-label="Permalink to &quot;Beam Search&quot;">​</a></h3><p>维护多个候选序列，每一步保留最好的 k 个&quot;光束&quot;。适合需要全局最优的场景（翻译等），但创造性差。</p><h2 id="实践建议" tabindex="-1">实践建议 <a class="header-anchor" href="#实践建议" aria-label="Permalink to &quot;实践建议&quot;">​</a></h2><p>对大多数场景，使用 <strong>Temperature 0.7 + Top-p 0.9</strong> 是不错的中庸起点。</p><table><thead><tr><th>场景</th><th>Temperature</th><th>Top-p</th><th>说明</th></tr></thead><tbody><tr><td>代码补全</td><td>0 ~ 0.2</td><td>0.95</td><td>确定性强</td></tr><tr><td>事实问答</td><td>0 ~ 0.3</td><td>0.9</td><td>避免编造</td></tr><tr><td>对话/聊天</td><td>0.7 ~ 1.0</td><td>0.9 ~ 0.95</td><td>自然多样</td></tr><tr><td>创意写作</td><td>0.8 ~ 1.2</td><td>0.95</td><td>启发性</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>Temperature=0 时模型一定会输出相同结果吗？</li><li>Top-k 和 Top-p 的核心区别？为什么现代 LLM 更偏好 Top-p？</li><li>如果需要模型生成代码，建议 Temperature 设为多少？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/text-generation" target="_blank" rel="noreferrer">OpenAI API: Text Generation</a></li><li><a href="https://huggingface.co/blog/how-to-generate" target="_blank" rel="noreferrer">How to generate text - Hugging Face</a></li></ul>',32)])])}const m=e(d,[["render",i]]);export{c as __pageData,m as default};
